insert into aura_exercise_catalog (id, payload, updated_at) values
  ('1F785091-F3A7-563C-B1C5-E5A793D1FB7B'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Barbell","hint":"","id":"1F785091-F3A7-563C-B1C5-E5A793D1FB7B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Quadriceps","Lower Back"],"name":"Trap Bar Deadlift","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and the trap bar on the ground in front of you.","Bend at the hips and knees to lower yourself down and grip the handles of the trap bar with an overhand grip.","Keep your back straight and chest up as you begin to lift the trap bar off the ground by extending your hips and knees.","As you lift, focus on driving through your heels and squeezing your glutes at the top of the movement.","Lower the trap bar back down to the ground by bending at the hips and knees, keeping your back straight throughout the movement.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"794D696B-1B11-5BEE-B55D-8771D617B578","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"16BC2A22-BB6C-5959-AF3E-5CAE12AE78E5","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"A7426A20-7B4E-5C08-8212-D41B0C068F8C","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"49B00620-C45A-592C-9E87-19EEF3513001","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('EC7306FC-B507-5B2F-8D69-D6458C1A174C'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"EC7306FC-B507-5B2F-8D69-D6458C1A174C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Triceps Dip","notes":"","plannedSets":3,"proTips":["Sit on the edge of a bench or chair with your hands gripping the edge, fingers pointing forward.","Slide your butt off the bench, supporting your weight with your hands.","Bend your elbows and lower your body towards the ground, keeping your back close to the bench.","Pause for a moment at the bottom, then push yourself back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"ED0B309D-5F91-597A-8ADC-46CFD09C3ABC","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('AAFEA6C0-DCFF-5C1F-9D6C-EA254C965B11'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"AAFEA6C0-DCFF-5C1F-9D6C-EA254C965B11","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Triceps Dip (Bench Leg)","notes":"","plannedSets":3,"proTips":["Sit on the edge of a bench with your hands gripping the edge, fingers pointing forward.","Walk your feet forward, sliding your butt off the bench, and straighten your arms.","Bend your elbows and lower your body towards the ground, keeping your back close to the bench.","Push through your palms to straighten your arms and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"7759B69D-6DF8-5165-85F5-07AF26B156BF","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('15D5D9F8-48DB-5D1D-8EE9-0752D88F3A6C'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"15D5D9F8-48DB-5D1D-8EE9-0752D88F3A6C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Triceps Dip (Between Benches)","notes":"","plannedSets":3,"proTips":["Sit on a bench with your hands gripping the edge of the bench, fingers pointing forward.","Slide your butt off the bench, supporting your weight with your hands.","Bend your elbows and lower your body towards the ground, keeping your back close to the bench.","Pause for a moment at the bottom, then push yourself back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"ED86CFF7-7165-5E6A-BA48-34AEC0BFE967","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('AAE61B05-22E9-5A83-9E51-D65735220F90'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"AAE61B05-22E9-5A83-9E51-D65735220F90","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Triceps Dips Floor","notes":"","plannedSets":3,"proTips":["Sit on the edge of a chair or bench with your hands next to your hips, fingers pointing forward.","Slide your butt off the front of the chair with your legs extended in front of you.","Straighten your arms, keeping a little bend in your elbows to keep tension on your triceps and off your elbow joints.","Slowly bend your elbows to lower your body toward the floor until your elbows are at about a 90-degree angle.","Once you reach the bottom of the movement, press down into the chair to straighten your elbows, returning to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"09D1536E-0947-5F16-B2DB-3CCDB4DE5AFE","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('83D7A5B4-38B8-5092-A429-F3A1EAD1ABF9'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"83D7A5B4-38B8-5092-A429-F3A1EAD1ABF9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Triceps Press","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and your knees slightly bent.","Extend your arms straight out in front of you, parallel to the ground.","Bend your elbows and lower your body towards the ground, keeping your upper arms close to your sides.","Pause for a moment at the bottom, then push yourself back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"14568680-A94B-5280-9374-26D56859924E","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0F9214A9-071C-51EF-B990-79BF205EE736'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"0F9214A9-071C-51EF-B990-79BF205EE736","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Triceps Stretch","notes":"","plannedSets":3,"proTips":["Stand or sit upright with your back straight.","Extend one arm overhead, bending it at the elbow.","Place your opposite hand on the bent elbow and gently pull it towards your head.","Hold the stretch for 15-30 seconds, feeling a gentle stretch in your triceps.","Release the stretch and repeat on the other arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"7395C886-C702-57E6-B3AF-F691CD7A187A","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('A2CB4F8E-C06B-5114-B8E6-BCA42C8A790C'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"A2CB4F8E-C06B-5114-B8E6-BCA42C8A790C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Tuck Crunch","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, lift your shoulder blades off the ground and bring your knees towards your chest, simultaneously curling your upper body towards your knees.","Pause for a moment at the top, then slowly lower your shoulder blades and extend your legs back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"56C2B8A0-4C4F-59AD-844C-550E533627AD","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('EC3F3682-1E33-594F-9F73-16699C9DB53A'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"EC3F3682-1E33-594F-9F73-16699C9DB53A","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Rhomboids","Rear Deltoids"],"name":"Twin Handle Parallel Grip Lat Pulldown","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position yourself facing the cable machine.","Grasp the handles with an overhand grip, hands shoulder-width apart.","Sit down and position your thighs under the thigh pads, keeping your feet flat on the floor.","Lean back slightly and keep your chest up, maintaining a neutral spine.","Pull the handles down towards your upper chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, feeling the contraction in your lats.","Slowly release the handles and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"72BB6B14-1C68-5C5B-B2B2-D6D86CE5BCF3","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"9C8636BE-F051-5B9F-8DFD-C65DEDB7B072","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B03CFA85-53A8-5A65-ADAA-56E76A5DFD2A'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"B03CFA85-53A8-5A65-ADAA-56E76A5DFD2A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Obliques","Hamstrings"],"name":"Twist Hip Lift","notes":"","plannedSets":3,"proTips":["Lie on your back with your knees bent and feet flat on the ground.","Place your hands by your sides for support.","Engage your glutes and lift your hips off the ground, forming a straight line from your knees to your shoulders.","While keeping your hips lifted, twist your lower body to the right side, bringing your knees towards the ground.","Return to the starting position and repeat the twist to the left side.","Continue alternating twists for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"AF2CF6CA-7AC1-500D-9CFC-6625736C7F29","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('7FB3960D-0B91-54FA-BCA4-54242CBA187A'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"7FB3960D-0B91-54FA-BCA4-54242CBA187A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques","Hip Flexors"],"name":"Twisted Leg Raise","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your legs extended and your arms by your sides.","Place your hands under your glutes for support.","Engage your abs and lift both legs off the ground, keeping them straight.","As you lift your legs, twist your hips to one side, bringing your legs towards your opposite shoulder.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat the movement, this time twisting your hips to the other side.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"5F2BB887-D824-5BDF-BBE7-986618A45049","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('53C97F39-7278-57A0-992F-690A9E242843'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"53C97F39-7278-57A0-992F-690A9E242843","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Spine","Hamstrings","Glutes"],"name":"Two Toe Touch","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and your arms extended out to the sides.","Bend forward at the waist, keeping your back straight and your knees slightly bent.","Reach down towards your toes with both hands, keeping your legs straight.","Pause for a moment at the bottom, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"22DE3249-3E22-5D2E-9897-DCFADA8776DE","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3D7B0585-5C41-5C69-9A99-53FA02BF99AE'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"3D7B0585-5C41-5C69-9A99-53FA02BF99AE","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Shoulders"],"name":"Upper Back Stretch","notes":"","plannedSets":3,"proTips":["Stand up straight with your feet shoulder-width apart.","Extend your arms straight in front of you, parallel to the ground.","Interlace your fingers and rotate your palms away from your body.","Slowly raise your arms overhead, keeping them straight and parallel to each other.","As you raise your arms, squeeze your shoulder blades together.","Hold the stretch for 15-30 seconds, then release and repeat."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"AEC40AE2-406E-521D-B988-A5C516E2CD64","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('C55FBB70-898C-5381-AC88-E621391F88EE'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"C55FBB70-898C-5381-AC88-E621391F88EE","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Spine","Shoulders","Chest"],"name":"Upward Facing Dog","notes":"","plannedSets":3,"proTips":["Lie face down on the floor with your legs extended behind you.","Place your hands on the floor next to your lower ribs, fingers pointing forward.","Press your hands firmly into the floor and straighten your arms, lifting your torso and thighs off the ground.","Roll your shoulders back and down, opening your chest and lifting your gaze towards the ceiling.","Hold this position for a few breaths, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"8B161340-7D58-5CBF-93B5-68DB4FA4B220","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D7E76F64-F7B9-5B66-8CC5-47536AACB93B'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"D7E76F64-F7B9-5B66-8CC5-47536AACB93B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"V-Sit On Floor","notes":"","plannedSets":3,"proTips":["Sit on the floor with your legs extended in front of you.","Lean back slightly and lift your legs off the ground, keeping them straight.","Simultaneously, lift your upper body off the ground and reach your arms towards your legs.","Hold this position for a few seconds, then slowly lower your upper body and legs back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"1E88B97F-F02B-5CCF-981A-6A99DDC45E6F","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1FB34F56-054D-545B-95BC-77257897260C'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"1FB34F56-054D-545B-95BC-77257897260C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Vertical Leg Raise (On Parallel Bars)","notes":"","plannedSets":3,"proTips":["Hang from the parallel bars with your arms fully extended and your body straight.","Engage your core and lift your legs up in front of you, keeping them straight.","Continue lifting until your legs are parallel to the ground or slightly higher.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"B714F240-2C99-5931-9B4B-5C2F89E4B079","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A6D6B723-03E3-5AEC-9CD3-1C66DDCC5EB7'::uuid, '{"category":"Cardio","difficulty":"Beginner","equipment":"Cardio Machine","hint":"","id":"A6D6B723-03E3-5AEC-9CD3-1C66DDCC5EB7","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Cardiovascular System","Quadriceps","Hamstrings","Glutes","Calves"],"name":"Walk Elliptical Cross Trainer","notes":"","plannedSets":3,"proTips":["Adjust the resistance level and incline of the elliptical machine to your desired settings.","Step onto the pedals of the machine and grip the handles lightly.","Begin by pushing down with your feet and pulling the handles towards your body.","Continue this motion, alternating between pushing and pulling, to simulate a walking or running motion.","Maintain a steady pace and keep your core engaged throughout the exercise.","Continue for the desired duration of your cardio workout.","Gradually decrease the intensity and speed of the machine before stepping off."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[],"type":"No Warmup Required"},"youtubeURL":""}'::jsonb, now()),
  ('CE39494A-F5C6-5D4C-BBA8-4201242DC2F9'::uuid, '{"category":"Cardio","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"CE39494A-F5C6-5D4C-BBA8-4201242DC2F9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Cardiovascular System","Quadriceps","Hamstrings","Glutes","Calves"],"name":"Walking High Knees Lunge","notes":"","plannedSets":3,"proTips":["Stand with your feet hip-width apart.","Lift your right knee up towards your chest as high as you can while balancing on your left leg.","Step forward with your right foot and lower your body into a lunge position, bending both knees to a 90-degree angle.","Push off with your right foot and bring your left knee up towards your chest.","Step forward with your left foot and lower your body into a lunge position.","Continue alternating legs and lunging forward, keeping your core engaged and maintaining a steady pace.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[],"type":"No Warmup Required"},"youtubeURL":""}'::jsonb, now()),
  ('9447483D-0A99-54EA-B2CE-835C153BB95C'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"9447483D-0A99-54EA-B2CE-835C153BB95C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Walking Lunge","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart.","Take a step forward with your right leg, lowering your body into a lunge position.","Keep your torso upright and your front knee aligned with your ankle.","Push off with your right foot and bring your left foot forward, stepping into a lunge position with your left leg.","Continue alternating legs and walking forward, maintaining a controlled and steady pace.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"714836A9-7AEF-5884-B4F1-E6605B2000B4","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('4DC634C7-8D59-5E8C-A376-44D58991FE54'::uuid, '{"category":"Cardio","difficulty":"Beginner","equipment":"Machine","hint":"","id":"4DC634C7-8D59-5E8C-A376-44D58991FE54","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Cardiovascular System","Quadriceps","Hamstrings","Calves"],"name":"Walking On Incline Treadmill","notes":"","plannedSets":3,"proTips":["Adjust the incline level on the treadmill to your desired intensity.","Stand on the treadmill with your feet shoulder-width apart.","Start walking at a comfortable pace, ensuring that you maintain proper form.","Engage your core muscles and keep your back straight throughout the exercise.","Continue walking on the incline treadmill for the desired duration of your cardio workout.","Gradually decrease the incline and speed of the treadmill to cool down before stopping."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[],"type":"No Warmup Required"},"youtubeURL":""}'::jsonb, now()),
  ('EC5FD01B-FCE9-5623-9BE8-03A43D871FE4'::uuid, '{"category":"Cardio","difficulty":"Beginner","equipment":"Cardio Machine","hint":"","id":"EC5FD01B-FCE9-5623-9BE8-03A43D871FE4","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Cardiovascular System","Quadriceps","Hamstrings","Glutes","Calves"],"name":"Walking On Stepmill","notes":"","plannedSets":3,"proTips":["Adjust the stepmill machine to a comfortable level.","Step onto the machine and place your hands on the handrails for support.","Start walking by placing one foot on a step and then the other, alternating between legs.","Maintain an upright posture and engage your core muscles.","Continue walking for the desired duration or distance.","Gradually increase the intensity or speed as you become more comfortable with the exercise.","Remember to cool down and stretch after completing the exercise."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[],"type":"No Warmup Required"},"youtubeURL":""}'::jsonb, now()),
  ('FB030743-9AE9-5366-9C7B-F63241285D78'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"FB030743-9AE9-5366-9C7B-F63241285D78","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Weighted Bench Dip","notes":"","plannedSets":3,"proTips":["Sit on a bench with your hands gripping the edge, fingers pointing forward.","Slide your butt off the bench, supporting your weight with your hands.","Lower your body by bending your elbows until your upper arms are parallel to the floor.","Push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"21A7433C-0EF7-5455-B42A-862F879B56CF","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('ADCF87CA-3B7D-5A47-A2CB-FB39BCEAD79C'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"ADCF87CA-3B7D-5A47-A2CB-FB39BCEAD79C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Forearms"],"name":"Weighted Close Grip Chin-Up On Dip Cage","notes":"","plannedSets":3,"proTips":["Stand in front of the dip cage and grab the parallel bars with an underhand grip, hands shoulder-width apart.","Hang from the bars with your arms fully extended, feet off the ground, and body straight.","Engage your back muscles and pull your body up towards the bars, keeping your elbows close to your sides.","Continue pulling until your chin is above the bars, then pause for a moment.","Slowly lower your body back down to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"0E737BE4-BD15-58A2-BBC4-026F17072379","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1A4E68C0-CB92-5785-961F-64581EFB96AE'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Bodyweight","hint":"","id":"1A4E68C0-CB92-5785-961F-64581EFB96AE","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Weighted Cossack Squats","notes":"","plannedSets":3,"proTips":["Stand with your feet wider than shoulder-width apart and toes pointing slightly outward.","Hold a weight in front of your chest with both hands.","Shift your weight to one side and lower your body by bending the knee of the side you shifted towards, while keeping the other leg straight.","Go as low as you can while maintaining balance and keeping your chest up.","Push through the heel of the bent leg to return to the starting position.","Repeat on the other side, alternating between legs."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"60B574B8-E8D5-568B-858C-2B6C1BAC8EE1","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('DBD9AFB7-DC6B-5EB7-A490-10BED43E3E80'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"DBD9AFB7-DC6B-5EB7-A490-10BED43E3E80","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques"],"name":"Weighted Crunch","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your knees bent and feet flat on the ground.","Hold a weight plate or dumbbell on your chest.","Engage your abs and lift your upper body off the ground, curling forward until your shoulder blades are off the ground.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"C4B5B91B-A6B6-53FB-9BFD-4BA5EB7BAC06","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('98315290-E84E-5C4B-983B-319943ED7F43'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"98315290-E84E-5C4B-983B-319943ED7F43","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors","Lower Back"],"name":"Weighted Decline Sit-Up","notes":"","plannedSets":3,"proTips":["Lie flat on a decline bench with your feet secured under the foot pads.","Place your hands behind your head or across your chest.","Engage your abs and slowly lift your upper body off the bench, curling forward until your torso is perpendicular to the ground.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"E5DBB03C-E7A2-51AD-B3EE-562A8F7536B8","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('597C1987-4118-5BD1-BB96-F9B79A06CAC5'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"597C1987-4118-5BD1-BB96-F9B79A06CAC5","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings","Glutes"],"name":"Weighted Donkey Calf Raise","notes":"","plannedSets":3,"proTips":["Stand on a raised platform with your toes on the edge and your heels hanging off.","Hold onto a stable object for support.","Raise your heels as high as possible by extending your ankles.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"2F373041-642E-58D6-91A5-1604F33943CF","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C9CD0533-608B-5B7A-8EE7-74712F6BBA72'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"C9CD0533-608B-5B7A-8EE7-74712F6BBA72","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Weighted Drop Push Up","notes":"","plannedSets":3,"proTips":["Start in a high plank position with your hands slightly wider than shoulder-width apart and your feet together.","Lower your chest towards the ground, keeping your elbows close to your body.","Once your chest is just above the ground, explosively push yourself up, lifting your hands off the ground.","As you push up, quickly move your hands out to the sides and slightly forward, allowing your body to drop down towards the ground.","Catch yourself with your hands in the wider position and immediately lower your chest towards the ground again.","Repeat the push-up motion, dropping down and catching yourself with your hands in the narrower position.","Continue alternating between the wider and narrower hand positions for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"FEA73B5D-1DAA-5B2A-8173-F662FF5622CC","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6BCCC50D-B6C9-53E1-A4CC-5923CF35D668'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"6BCCC50D-B6C9-53E1-A4CC-5923CF35D668","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Shoulders","Lower Back"],"name":"Weighted Front Plank","notes":"","plannedSets":3,"proTips":["Start by lying face down on the floor.","Place your forearms on the ground, with your elbows directly under your shoulders.","Extend your legs straight out behind you, with your toes on the ground.","Engage your core and lift your body off the ground, balancing on your forearms and toes.","Keep your body in a straight line from your head to your heels.","Hold this position for the desired amount of time.","Lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"08AE1247-A3BE-5867-A88C-88EAB99DBEF1","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('16B70DA5-1410-56E0-B3AA-38F567E6EE05'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"16B70DA5-1410-56E0-B3AA-38F567E6EE05","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Biceps","Forearms"],"name":"Weighted Front Raise","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your thighs.","Keeping your arms straight, exhale and lift the dumbbells in front of you until they are at shoulder level.","Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"E0ECB4FF-7E8B-558E-82D9-06FB5876F95A","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('298474CA-D3AD-5F03-9140-C59FB4741537'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"298474CA-D3AD-5F03-9140-C59FB4741537","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors","Lower Back"],"name":"Weighted Hanging Leg-Hip Raise","notes":"","plannedSets":3,"proTips":["Hang from a pull-up bar with your arms fully extended and your palms facing away from you.","Engage your core and lift your legs up in front of you, keeping them straight.","Continue lifting until your legs are parallel to the ground or slightly higher.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"C464E050-A576-564D-9F4D-F9AF24099F6B","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E4832470-A18F-596D-8F7A-F21C54A85AEE'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"E4832470-A18F-596D-8F7A-F21C54A85AEE","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Spine","Glutes","Hamstrings"],"name":"Weighted Hyperextension (On Stability Ball)","notes":"","plannedSets":3,"proTips":["Position yourself face down on a stability ball with your hips resting on the ball and your feet against a wall for stability.","Place your hands behind your head or cross them over your chest.","Engage your core and slowly lift your upper body off the ball, extending your back until your body forms a straight line.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"C2730746-C0B7-58A7-B20B-97EE85FC5FA5","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('7BA2CC3B-3A86-5279-A5E1-AE907FBB4FB1'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"7BA2CC3B-3A86-5279-A5E1-AE907FBB4FB1","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Core"],"name":"Weighted Kneeling Step With Swing","notes":"","plannedSets":3,"proTips":["Start in a kneeling position with your knees hip-width apart and your back straight.","Hold a weight in each hand, with your arms extended straight down in front of you.","Engage your core and swing the weights up and overhead, keeping your arms straight.","Lower the weights back down to the starting position and repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"4A6E6930-9092-5825-8761-10A6A1C79611","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('87B28F6B-6B1D-5B1B-83B8-B0EA7B26CA5B'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"87B28F6B-6B1D-5B1B-83B8-B0EA7B26CA5B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Weighted Lunge With Swing","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a weight in each hand.","Take a step forward with your right foot, lowering your body into a lunge position.","As you lunge forward, swing the weights forward and upward, keeping your arms straight.","Push off with your right foot and return to the starting position, swinging the weights back down.","Repeat with your left foot and continue alternating legs for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"5EA56D1A-58D0-561C-8914-B64B18125426","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('98855EBB-24DC-5D6E-93D0-F83ACAD7DBC1'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"98855EBB-24DC-5D6E-93D0-F83ACAD7DBC1","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Triceps","Shoulders","Chest"],"name":"Weighted Muscle Up","notes":"","plannedSets":3,"proTips":["Start by hanging from a pull-up bar with your palms facing away from you and your hands slightly wider than shoulder-width apart.","Engage your core and pull your body up towards the bar, leading with your chest.","As you reach the top of the movement, transition your grip so that your palms are facing towards you.","Continue pulling yourself up until your chest reaches the bar, then pause for a moment.","Slowly lower yourself back down to the starting position, maintaining control throughout the movement.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"FB23921E-CC02-5E2F-AF19-44166546E525","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B19687D6-D1D8-5004-8990-36D97C8B2527'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"B19687D6-D1D8-5004-8990-36D97C8B2527","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Triceps","Shoulders","Forearms"],"name":"Weighted Muscle Up (On Bar)","notes":"","plannedSets":3,"proTips":["Start by hanging from a pull-up bar with your palms facing away from you and your hands slightly wider than shoulder-width apart.","Engage your core and pull your shoulder blades down and back.","Bend your elbows and pull your chest towards the bar, keeping your body straight.","Once your chest reaches the bar, push down with your hands and drive your elbows back, lifting your body above the bar.","Pause at the top of the movement, then slowly lower yourself back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F4289663-5EEB-581B-8211-7BAC699159B2","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3425B8A2-B2A8-5924-B0CD-F1E4702F1D98'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"3425B8A2-B2A8-5924-B0CD-F1E4702F1D98","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Forearms"],"name":"Weighted One Hand Pull Up","notes":"","plannedSets":3,"proTips":["Grab the pull-up bar with an overhand grip, slightly wider than shoulder-width apart.","Hang from the bar with your arm fully extended and your body straight.","Engage your core and pull your body up towards the bar by bending your elbow and squeezing your back muscles.","Continue pulling until your chin is above the bar.","Lower your body back down to the starting position with control.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"E3242153-ECF4-5915-BFB9-EDA85F4467E2","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('DB893BAC-0C06-55D4-8271-9340A46C647D'::uuid, '{"category":"Core","difficulty":"Intermediate","equipment":"Bodyweight","hint":"","id":"DB893BAC-0C06-55D4-8271-9340A46C647D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques","Lower Back"],"name":"Weighted Overhead Crunch (On Stability Ball)","notes":"","plannedSets":3,"proTips":["Sit on a stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Hold a weight plate or dumbbell with both hands and extend your arms overhead.","Engage your abs and slowly curl your torso forward, bringing your chest towards your knees.","Pause for a moment at the top, then slowly lower your torso back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"26806338-2856-5C3F-9F7B-3F3B5F7AEA42","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('98EE369E-B93B-534C-AFB5-8AD2BFA276AA'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"98EE369E-B93B-534C-AFB5-8AD2BFA276AA","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Forearms"],"name":"Weighted Pull-Up","notes":"","plannedSets":3,"proTips":["Grab the pull-up bar with an overhand grip, slightly wider than shoulder-width apart.","Hang from the bar with your arms fully extended and your body straight.","Engage your back muscles and pull your body up towards the bar, keeping your elbows close to your body.","Continue pulling until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"96BB054F-54A9-5EB8-8CC2-C7A0E7FA0F36","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('009B7356-C798-57D9-B43F-BE212AFE94E0'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"009B7356-C798-57D9-B43F-BE212AFE94E0","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Upper Back"],"name":"Weighted Round Arm","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Raise your arms out to the sides, keeping a slight bend in your elbows.","Continue lifting your arms until they are parallel to the ground.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"82ACF9C7-1277-554E-9622-571B07F862EE","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B9C12904-A7B7-5628-AA13-C19566325CDF'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"B9C12904-A7B7-5628-AA13-C19566325CDF","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques","Lower Back"],"name":"Weighted Russian Twist","notes":"","plannedSets":3,"proTips":["Sit on the ground with your knees bent and your feet flat on the floor.","Hold a weight or medicine ball with both hands in front of your chest.","Lean back slightly, keeping your back straight and your core engaged.","Slowly twist your torso to the right, bringing the weight or medicine ball towards the floor on your right side.","Pause for a moment, then twist your torso to the left, bringing the weight or medicine ball towards the floor on your left side.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"D2642381-CACE-59C9-A53D-0BDD89594FD1","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('5F0818BD-2740-559E-AB80-9BB24AB64C77'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"5F0818BD-2740-559E-AB80-9BB24AB64C77","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques","Hip Flexors"],"name":"Weighted Russian Twist (Legs Up)","notes":"","plannedSets":3,"proTips":["Sit on the ground with your knees bent and feet lifted off the ground, keeping your legs together.","Hold the weight with both hands in front of your chest, keeping your elbows slightly bent.","Lean back slightly to engage your core muscles.","Twist your torso to the right, bringing the weight towards the ground on your right side.","Pause for a moment, then twist your torso to the left, bringing the weight towards the ground on your left side.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"970FC8D1-C123-56EA-9079-D800B4A03FD9","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0D3FC925-BB97-5F95-8A19-B2A268916DD4'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"0D3FC925-BB97-5F95-8A19-B2A268916DD4","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques","Lower Back"],"name":"Weighted Russian Twist V. 2","notes":"","plannedSets":3,"proTips":["Sit on the ground with your knees bent and feet flat on the floor.","Hold the weight with both hands in front of your chest.","Lean back slightly to engage your core muscles.","Twist your torso to the right, bringing the weight towards the right side of your body.","Pause for a moment, then twist your torso to the left, bringing the weight towards the left side of your body.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"0E2286F1-EB1C-51B7-8E2D-07B71D8289F8","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('7CE5792C-F2C5-5FC3-BDF9-0B0CC79C7FA7'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Medicine Ball","hint":"","id":"7CE5792C-F2C5-5FC3-BDF9-0B0CC79C7FA7","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Weighted Seated Bicep Curl (On Stability Ball)","notes":"","plannedSets":3,"proTips":["Sit on a stability ball with your feet flat on the ground and your back straight.","Hold a medicine ball with an underhand grip, palms facing up, and let your arms hang down by your sides.","Keeping your upper arms stationary, exhale and curl the medicine ball up towards your shoulders.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the medicine ball back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F3160D98-93CB-598B-B218-F1C5546ACDF7","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('EB33D2F8-9E0D-5939-BFBD-DDE69A129523'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"EB33D2F8-9E0D-5939-BFBD-DDE69A129523","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques","Lower Back"],"name":"Weighted Seated Twist (On Stability Ball)","notes":"","plannedSets":3,"proTips":["Sit on a stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Hold a weight plate or dumbbell with both hands close to your chest.","Engage your core and slowly rotate your torso to one side, keeping your hips stable.","Pause for a moment at the end of the rotation, then slowly return to the starting position.","Repeat the rotation to the other side.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"316F9E9F-D02A-5D97-8903-CD00E1319F2A","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1462AFAE-90BF-5394-A53C-7094CF8830FF'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"1462AFAE-90BF-5394-A53C-7094CF8830FF","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques","Lower Back"],"name":"Weighted Side Bend (On Stability Ball)","notes":"","plannedSets":3,"proTips":["Sit on a stability ball with your feet shoulder-width apart and flat on the ground.","Hold a weight in one hand and place your other hand on your hip.","Engage your core and slowly bend sideways towards the weighted side, keeping your back straight.","Pause for a moment at the bottom, then slowly return to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"3056C93F-8356-50E0-B223-699A18AD3658","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('09DD2D80-2AB6-5F34-B407-2A5DB250E3DE'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Bodyweight","hint":"","id":"09DD2D80-2AB6-5F34-B407-2A5DB250E3DE","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Glutes","Hamstrings","Calves"],"name":"Weighted Sissy Squat","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and your toes pointing slightly outward.","Hold a weight in front of your chest with both hands, or place a barbell across your upper back.","Keeping your chest up and your core engaged, slowly lower your body down by bending at the knees and hips.","Continue lowering until your thighs are parallel to the ground or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"569456DA-EC40-538B-9CD0-B7A168314A57","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B591D4A1-33EC-5D68-9005-C4C769DC64A1'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Bodyweight","hint":"","id":"B591D4A1-33EC-5D68-9005-C4C769DC64A1","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Weighted Squat","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, toes pointing slightly outward.","Hold a weight in front of your chest or on your shoulders.","Engage your core and keep your chest up as you lower your hips down and back, as if sitting into a chair.","Lower until your thighs are parallel to the ground, or as low as you can comfortably go.","Push through your heels to stand back up, squeezing your glutes at the top.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"AA17B5A4-5319-5D65-8E02-6075DD7B7C49","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('16975255-DE60-557E-809B-65864BFAE415'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"16975255-DE60-557E-809B-65864BFAE415","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Weighted Standing Curl","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing forward.","Keep your elbows close to your torso and exhale as you curl the weights up to shoulder level.","Pause for a moment at the top, then inhale as you slowly lower the weights back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"6241A4F3-129A-5C03-B29C-163B0B026910","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('DBF611FF-1AB8-5CDE-9F4A-5E51392F051A'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"DBF611FF-1AB8-5CDE-9F4A-5E51392F051A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms","Biceps","Triceps"],"name":"Weighted Standing Hand Squeeze","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a weight in each hand.","Extend your arms straight in front of you, palms facing each other.","Squeeze your hands together as hard as you can, engaging your forearms.","Hold the squeeze for a few seconds, then release.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"DAE8EAAA-D069-5263-911C-F0B07ECEA9A8","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6EE18CAD-6D51-5F08-BEFB-69D09BB526F7'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"6EE18CAD-6D51-5F08-BEFB-69D09BB526F7","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Weighted Straight Bar Dip","notes":"","plannedSets":3,"proTips":["Position yourself between parallel bars with your arms fully extended and your body straight.","Lower your body by bending your elbows until your upper arms are parallel to the ground.","Pause for a moment, then push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"7F81D9EB-6640-5E04-9F1A-4E9F5148A3F9","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('8A191B72-E10A-549F-9782-2D9F0C107CA2'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"8A191B72-E10A-549F-9782-2D9F0C107CA2","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Weighted Stretch Lunge","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart.","Take a step forward with your right foot, keeping your back straight.","Lower your body by bending your knees until your right thigh is parallel to the ground.","Push through your right heel to return to the starting position.","Repeat with your left leg.","Continue alternating legs for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"987EDD5E-C9FC-5EA1-929C-8E8784013AAA","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('12679189-2B4B-524B-98AE-84FB6FB0EB10'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"12679189-2B4B-524B-98AE-84FB6FB0EB10","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Weighted Svend Press","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a weight plate in front of your chest with both hands.","Keep your elbows slightly bent and your palms facing each other.","Press the weight plate straight out in front of you, fully extending your arms.","Pause for a moment at the end of the movement, then slowly bring the weight plate back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"1A21794C-D1ED-5B04-B572-A3F1FF3F2EBE","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('8DED3625-759D-56DD-A53B-809B073784FA'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"8DED3625-759D-56DD-A53B-809B073784FA","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Weighted Three Bench Dips","notes":"","plannedSets":3,"proTips":["Sit on the edge of a bench with your hands gripping the edge, fingers pointing forward.","Walk your feet forward, sliding your butt off the bench and supporting your weight with your arms.","Lower your body by bending your elbows, keeping your back close to the bench.","Pause for a moment at the bottom, then push yourself back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"25B0CB59-4C96-5DAE-A59E-FB3C2A6E9987","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('881373FF-4FD0-5ACA-8659-4350593C8E2D'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"881373FF-4FD0-5ACA-8659-4350593C8E2D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Weighted Tricep Dips","notes":"","plannedSets":3,"proTips":["Sit on the edge of a bench or chair with your hands gripping the edge next to your hips.","Slide your butt off the front of the bench with your legs extended in front of you.","Keep your back close to the bench and your elbows slightly bent.","Lower your body by bending your elbows until your upper arms are parallel to the floor.","Push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"621645B2-86EB-5C6D-A2D9-355A4AAB9513","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('68EE6E01-14A6-5C25-BB15-F387DE825EA9'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"68EE6E01-14A6-5C25-BB15-F387DE825EA9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Weighted Triceps Dip On High Parallel Bars","notes":"","plannedSets":3,"proTips":["Position yourself between two parallel bars with your hands gripping the bars and your arms fully extended.","Bend your elbows and lower your body until your upper arms are parallel to the ground.","Pause for a moment, then push through your palms to straighten your arms and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"9FB962A1-41CD-5311-92C2-1EC448FFC2FE","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('670A146C-69B2-5218-88E2-D576E48DE31D'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Roller","hint":"","id":"670A146C-69B2-5218-88E2-D576E48DE31D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Lower Back"],"name":"Wheel Rollerout","notes":"","plannedSets":3,"proTips":["Kneel on the floor and place the wheel roller in front of you.","Place your hands on the handles of the wheel roller and extend your arms straight out in front of you.","Engage your core muscles and slowly roll the wheel forward, keeping your back straight and your abs tight.","Continue rolling forward until your body is fully extended and your arms are overhead.","Pause for a moment, then slowly roll the wheel back towards your knees, maintaining control and keeping your abs engaged.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"E844AB4B-D90A-57E4-BA15-657F191AD2B9","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D777CE45-A418-53F1-A64E-95D8C11EF889'::uuid, '{"category":"Cardio","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"D777CE45-A418-53F1-A64E-95D8C11EF889","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Cardiovascular System","Quadriceps","Hamstrings","Calves"],"name":"Wheel Run","notes":"","plannedSets":3,"proTips":["Start in a plank position with your hands on the wheel and your body straight.","Engage your core and start rolling the wheel forward by extending your arms.","Continue rolling until your body is fully extended and your arms are overhead.","Reverse the movement by pulling the wheel back towards your body, using your core and arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[],"type":"No Warmup Required"},"youtubeURL":""}'::jsonb, now()),
  ('E27C2587-0C00-51DD-8DA6-332230D8D9F9'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"E27C2587-0C00-51DD-8DA6-332230D8D9F9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Forearms"],"name":"Wide Grip Pull-Up","notes":"","plannedSets":3,"proTips":["Hang from a pull-up bar with your palms facing away from you and your hands wider than shoulder-width apart.","Engage your core and squeeze your shoulder blades together.","Pull your body up towards the bar until your chin is above the bar.","Lower your body back down to the starting position with control.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"827D1BC5-5337-5627-A98E-D90C6EE93518","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0359B576-F7D9-5915-82D8-9AE3B601C3DB'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"0359B576-F7D9-5915-82D8-9AE3B601C3DB","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Forearms"],"name":"Wide Grip Rear Pull-Up","notes":"","plannedSets":3,"proTips":["Grab the pull-up bar with a wide overhand grip, hands slightly wider than shoulder-width apart.","Hang from the bar with your arms fully extended and your body straight.","Engage your back muscles and pull your body up towards the bar, leading with your chest.","Continue pulling until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"DB9718C6-29D0-5E66-99E7-021E45A807F6","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1E570EAF-6A6C-5148-9222-301746E68BD3'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"1E570EAF-6A6C-5148-9222-301746E68BD3","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Wide Hand Push Up","notes":"","plannedSets":3,"proTips":["Start in a high plank position with your hands wider than shoulder-width apart.","Keep your body in a straight line from head to toe.","Lower your chest towards the ground by bending your elbows, keeping them close to your sides.","Push through your palms to extend your arms and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"68B724D8-6238-5BB4-8EB4-55C37C07074E","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A7ADBD2B-7DC2-5D29-92C5-D665563630A0'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"A7ADBD2B-7DC2-5D29-92C5-D665563630A0","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Wide-Grip Chest Dip On High Parallel Bars","notes":"","plannedSets":3,"proTips":["Position yourself on the parallel bars with your arms fully extended and your body suspended in the air.","Lean forward slightly and lower your body by bending your elbows until your chest is just above the bars.","Pause for a moment, then push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"31E0D0C8-2AE0-5040-A734-2E8619DB7229","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('ADD84265-04B8-5440-B2C5-EB527DCC887D'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"ADD84265-04B8-5440-B2C5-EB527DCC887D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Quadriceps","Hamstrings","Calves"],"name":"Wind Sprints","notes":"","plannedSets":3,"proTips":["Find an open space or a track to perform the exercise.","Start by standing with your feet shoulder-width apart.","Begin running as fast as you can, pumping your arms and driving your knees up.","Continue sprinting for a specific distance or time period.","Rest and repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"4ABD8386-3069-52C6-8E24-F7DD5F896D9E","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1399A66E-3EED-5D81-AA15-95CD181BCB92'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"1399A66E-3EED-5D81-AA15-95CD181BCB92","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Hamstrings","Glutes","Quadriceps","Calves"],"name":"World Greatest Stretch","notes":"","plannedSets":3,"proTips":["Start in a lunge position with your right foot forward and your left foot back.","Place your hands on the ground on either side of your right foot.","Lower your left knee to the ground and extend your right leg, keeping your right foot flat on the ground.","Rotate your torso to the right, reaching your right arm up towards the ceiling.","Hold this position for a few seconds, then return to the starting position.","Switch sides and repeat the stretch with your left foot forward."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"EA690C3D-1A6C-5BB1-9FE2-D3D4405072E9","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('1498510D-9FD1-5D75-9423-9B1B8A8D36F4'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"1498510D-9FD1-5D75-9423-9B1B8A8D36F4","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms","Hands","Wrists"],"name":"Wrist Circles","notes":"","plannedSets":3,"proTips":["Extend your arms straight out in front of you.","Make a fist with both hands.","Rotate your wrists in a circular motion, keeping your arms still.","Continue the wrist circles for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"C74751E8-B06E-5165-809D-D1FB5C18FBAA","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('3B2B2368-B7AE-5376-9BD9-32CB445A5FE8'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"3B2B2368-B7AE-5376-9BD9-32CB445A5FE8","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms","Biceps","Triceps"],"name":"Wrist Rollerer","notes":"","plannedSets":3,"proTips":["Attach a weight to one end of a rope or bar.","Hold the other end of the rope or bar with both hands, palms facing down.","Stand with your feet shoulder-width apart and your arms fully extended in front of you.","Slowly roll the weight up towards your hands by flexing your wrists.","Pause for a moment at the top, then slowly lower the weight back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"9AF0DA31-83C3-532F-B8C2-3A4E5C209BC5","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now())
